var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"막아라! 그루터기를 지켜!","JPN":"止めろ！　切り株を守れ！","ENG":"Defend! Protect the Stump!","TWN":"攔住它們！保護木墩！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"으아앗! 누가 나 좀…!","JPN":"うわあっ！　誰か……！","ENG":"Aaargh! Somebody...!","TWN":"啊啊！誰來幫幫我…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"카롤리스! 혼자 일어날 수 있지?","JPN":"カロリス！　一人で立てるよね？","ENG":"Karolis! Can you get up?","TWN":"卡羅黎斯！你能自己站起來嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…당연하지.","JPN":"……当たり前じゃん。","ENG":"…Sure.","TWN":"我…我可以！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아이들을 데리고 연구소로 가! 여긴 우리가 막을 테니까!","JPN":"子どもたちを連れて研究所まで行って！　ここはあたしたちが止めるから！","ENG":"Take the children to the lab! We'll fend them off here!","TWN":"帶孩子們去研究室！這裡交給我們！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…알겠어!","JPN":"……わかった！","ENG":"...Okay!","TWN":"…知道了！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그리고…","JPN":"あと……","ENG":"And...","TWN":"還有…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"절대 죽으면 안 돼!","JPN":"絶対に死ぬなよ！","ENG":"don't die!","TWN":"千萬不能死！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"바보야. 성자는 안 죽어.","JPN":"バカ。聖者は死なないよ。","ENG":"You idiot. Helgons don't die.","TWN":"笨蛋，聖者是不會死的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"쳇…! 포위당한 채로는 반격이 쉽지 않아.","JPN":"ちっ……！　囲まれたままだとなかなか反撃できないね。","ENG":"Tch...! It's hard to counterattack while being surrounded like this.","TWN":"咳…！被包圍了不容易反擊。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이대로 가다간 주민들이 대피하기도 전에 뚫리겠어.","JPN":"このままじゃ、住民が避難する前に突破されちゃう。","ENG":"At this rate, our defense will be broken before the villagers all evacuate.","TWN":"這樣下去，居民們還沒來得及撤離就會被突破。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"이만하면 전력은 다 파악된 것 같군요.","JPN":"そちらの戦力はもう把握済みです。","ENG":"I believe I have your forces figured out now.","TWN":"我已經看透你們的戰術了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"사수. 1열, 2열. 일발 장전.","JPN":"射手。1列、2列。一発装填。","ENG":"Shooters in rows 1 and 2, load.","TWN":"狙擊手，第一排、第二排，裝彈準備…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"매복…?!","JPN":"待ち伏せ……！？","ENG":"An ambush...?!","TWN":"這是…埋伏？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VICTIM_ROOT_NPC_DEMON","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"아직도 저렇게 많은 적이 숨어 있었다고?!","JPN":"まだあんなに多くの敵が隠れていただと！？","ENG":"There were this many enemies in hiding?!","TWN":"怎麼會有這麼多敵人藏著？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VICTIM_ROOT_NPC_DEMON","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"안돼…! 지금 쏘면 사람들이…!","JPN":"ダメ……！　今撃つと他の人が……！","ENG":"No...! If they shoot now, the villagers will–!","TWN":"不行…！開始射擊的話，村民們就…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"방금 그 소린…?","JPN":"今の音は……？","ENG":"What was that sound...?","TWN":"剛才那聲音是…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"매복병들이… 차례대로 쓰러지고 있어?","JPN":"待ち伏せの兵が……次々と倒れてく？","ENG":"The ambushers... They are falling one after another?","TWN":"埋伏的敵人…一個接一個倒下了？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VICTIM_ROOT_NPC_DEMON","face":"UNIT_IDLE"},"C":{"char_id":"KEEPER_ROOT_NPC_MAM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"이런.","JPN":"おっと。","ENG":"Dammit.","TWN":"可惡。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VICTIM_ROOT_NPC_DEMON","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"진작 도망친 줄 알았건만…","JPN":"もう逃げたと思っていたが……","ENG":"I thought she was long gone by now...","TWN":"還以為早就逃跑了…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VICTIM_ROOT_NPC_DEMON","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"이쪽에서 먼저 패를 꺼내길 기다린 건가?","JPN":"こちらが先にカードを見せるのを待っていたのか？","ENG":"Were you waiting for me to show my cards first?","TWN":"是在等我亮出底牌嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VICTIM_ROOT_NPC_DEMON","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"악마의 하수인들은 악마의 지령에만 복종하지.","JPN":"悪魔の手下は悪魔の指示だけに従う。","ENG":"A devil's henchmen only respond to the devil's orders.","TWN":"魔鬼的手下只會服從魔鬼的命令。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"반대로 말해, 그 주인이 어딜 노려야 할지 모르면 공격도 지시하지 못하는 거야.","JPN":"逆に言うと、悪魔がどこを狙うかわかっていないと指示ができない。","ENG":"In other words, if the commander does not know where to aim, they cannot attack.","TWN":"反過來說，如果它們的主人不知道該攻擊哪裡，就無法下達指令。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"과연… 맹점을 제대로 노렸군요.","JPN":"なるほど……ちゃんと弱点を狙っていたのですね。","ENG":"I see... So you targeted our weakness.","TWN":"果然…你準確地抓住了弱點。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이대로 소멸시키기 전에, 네 심장을 어디에 숨겼는지 말해줄래?","JPN":"このまま消滅する前に、アナタの心臓をどこに隠したのか話してくれるかしら？","ENG":"Before I rid of you from this world, do you mind telling me where you hid your heart?","TWN":"在你被消滅之前，能告訴我你把心臟藏在哪裡嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"어차피 악마에겐 필요도 없는 물건이잖니?","JPN":"どうせ悪魔には要らないものでしょう？","ENG":"After all, a devil has no use for it, no?","TWN":"反正那東西對魔鬼來說也沒用，不是嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"후후… 황금가지를 원하나요?","JPN":"ふふ……黄金の枝がほしいのですか？","ENG":"Haha... You seek the Golden Branch?","TWN":"呵呵…你想要金枝嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"유감이지만, 그건 이미 마왕에게 있습니다.","JPN":"残念ですが、それはすでに魔王の元にあります。","ENG":"A pity that it is already in the hands of the Demon Lord.","TWN":"很遺憾，那已經在魔王手裡了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"마왕이… 황금가지를 갖고 있다고?","JPN":"魔王が……黄金の枝を？","ENG":"The Demon Lord... is in possession of the Golden Branch?","TWN":"金枝…在魔王手裡？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"앗, 악마가 사라졌어?","JPN":"あっ、悪魔が消えた？","ENG":"Huh?! The devil disappeared!","TWN":"啊，魔鬼消失了？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나…! 뒤를…!","JPN":"モルガナ……！　後ろ……！","ENG":"Morgana...! Behind you...!","TWN":"莫甘娜…！小心後面…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐?","JPN":"はあ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"꺄아아악!!","JPN":"キャアアッ！","ENG":"KYAAAAH!!","TWN":"呃啊啊阿！！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"아가씨!","JPN":"お嬢様！","ENG":"Miss Morgana!","TWN":"小姐！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"뭐야? 네 녀석이 어떻게 그런 능력을…?!","JPN":"何？　どうしてアナタがそんな能力を……！？","ENG":"What? How do you have such abilities...?!","TWN":"什麼？你什麼時候有的那種能力…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"재밌군요.","JPN":"面白いですね。","ENG":"Interesting.","TWN":"有意思。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"악마를 안다고 자부하던 당신이 그렇게 당황할 줄이야.","JPN":"悪魔のことには詳しいはずでは？","ENG":"I did not think to see someone who prided herself on knowing devils to be so flustered.","TWN":"自稱瞭解魔鬼的你，竟然會如此慌張。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 힘은 설마… 마왕의 권능? 악마가 마왕과 계약했다고?","JPN":"その力はまさか……魔王の権能？　悪魔が魔王と契約したの？","ENG":"That power... is that the Demon Lord's power? A devil made a pact with a Demon Lord?","TWN":"那股力量難道是…魔王的權能？你和魔王簽訂了契約？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"당신 말처럼, 악마인 저에게 인간의 소원을 이뤄주는 황금가지 따윈 아무 쓸모가 없어요.","JPN":"あなたの言うとおり、悪魔である私に人間の願いを叶る黄金の枝など何の役にも立ちません。","ENG":"As you have said, the Golden Branch that grants the wishes of humans is of no use for devils like me.","TWN":"就像你說的，作為魔鬼的我，金枝對我毫無用處。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"그래서 마왕에게 넘기고 그 힘을 대가로 받았죠.","JPN":"なので魔王に渡し、対価としてこの力を授かったのです。","ENG":"That is why I offered it to the Demon Lord and was granted this power in return.","TWN":"所以我把它交給了魔王，並以此換取了力量。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너…!","JPN":"アナタ……！","ENG":"You...!","TWN":"你…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"위험합니다! 제사장님! 혼자 악마에게 다가가시면…!","JPN":"危険です！　司祭長！　一人で悪魔に近づいては……！","ENG":"It's too dangerous! High Priest! If you approach the devil by yourself–!","TWN":"危險！祭司長！一個人靠近魔鬼的話…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"음?!","JPN":"むっ！？","ENG":"Hmm?!","TWN":"呃？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"어디서 이런 괴력이…?","JPN":"どこからこんな怪力が……？","ENG":"What is this power...?","TWN":"這股阻力是從哪來的…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"여기서…!","JPN":"ここで……！","ENG":"I SHALL...!","TWN":"我會在這裡…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"소멸시켜주지!","JPN":"消滅させてやるわ！","ENG":"DESTROY YOU HERE!","TWN":"毀滅你！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_03"},{"id":"L41_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"그 눈은…?","JPN":"その目は……？","ENG":"Those eyes…?","TWN":"那雙眼睛是…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"흥미롭네요. 인간들을 보살피던 당신의 정체가… 사실은 악마였다니.","JPN":"興味深いですね。人間の世話をしていたあなたの正体が……実は悪魔だったとは。","ENG":"Interesting. The identity of the being who takes care of humans is... none other than a devil herself.","TWN":"真有趣，一直照顧人類的你，真實身份竟然是魔鬼。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"큭…!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"咳…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"영혼도 없는 악마 주제에, 나무의 가능성을 빌려 이성을 유지하고 있었던 겁니까?","JPN":"魂のない悪魔のくせに、木の可能性を借り理性を保っていたのですか？","ENG":"You soulless devil. Have you been maintaining your sanity by borrowing the tree's possibilities?","TWN":"沒有了靈魂的魔鬼，借助樹的力量維持著理智嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"왜 그런 쓸데없는 짓을 하죠? 제가 아는 요정 멀린은 인간을 누구보다 증오하고 있었을 텐데요.","JPN":"なぜそんな余計なことを？　私の知る妖精マーリンは、誰より人間を憎悪していたはずです。","ENG":"Why do such meaningless acts? The fairy Merlin I knew hated humans more than anyone.","TWN":"為什麼要做這種無聊的事？我認識的精靈梅林，應該是最憎恨人類的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"악마 주제에…","JPN":"悪魔のくせに……","ENG":"You devil...","TWN":"身為魔鬼…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"멋대로 넘겨짚기는…!","JPN":"勝手に解釈するな……！","ENG":"how dare you think you know–!","TWN":"別隨便猜測…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"하긴, 당신이 <color=#ffd34c>모든</color> 인간을 증오하는 건 아니었죠.","JPN":"そうでした。あなたは<color=#ffd34c>すべての</color>人間を憎悪しているわけではありませんでしたね。","ENG":"Then again, you did not hate <color=#ffd34c>all</color> humans.","TWN":"確實，你並不憎恨<color=#ffd34c>所有</color>人類。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"그겁니까? 악마가 되어서도 사랑했던 이를 잊지 못해, 집착을 부리는 건가요?","JPN":"あれですか？　悪魔になっても愛する人を忘れられず、今でも固執しているのですか？","ENG":"Is that your reason? Is your obsession stemming from your inability to let go of your beloved's memory even after turning into a devil?","TWN":"是因為這個嗎？就算成為魔鬼，也無法忘記曾經愛過的人，所以才如此執著嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 입을… 머리째 찢어주지!","JPN":"その口……頭ごとに破いてやる！","ENG":"I shall rip that mouth of yours... straight from your head!","TWN":"我會把你的嘴…連同腦袋一起撕碎！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"…이런. 강하군요.","JPN":"……おっと。強いですね。","ENG":"...Oh, my. What brute strength.","TWN":"…令人驚歎的力量。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"그루터기만 남았어도, 황금나무는 황금나무란 걸까요?","JPN":"切り株だけになっても、黄金の木は黄金の木ということでしょうか。","ENG":"Although just a stump, the Golden Tree is still the Golden Tree, I see.","TWN":"看來就算只剩下木墩，黃金樹依然是黃金樹嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"이번엔 물러서는 게 좋겠네요. 세상의 종말을 목도하기도 전에 사라지고 싶진 않으니까요.","JPN":"今回は下がった方がよさそうですね。世界の終末を目にする前に消えたくはないので。","ENG":"It would be best for me to back off this time. For I will not want to die before witnessing the world's end.","TWN":"這次就退後一步，我可不想在目睹世界末日之前就消失。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"도망쳐도 소용없어. 넌 내가 끝까지 쫓아가서 없앤다.","JPN":"逃げても無駄よ。アナタはアタシが最後まで追いかけて殺すわ。","ENG":"There is no use running away. I will chase you to the end and kill you myself.","TWN":"逃跑也沒用…我會追到天涯海角把你消滅。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"원한다면 말리진 않겠습니다만…","JPN":"望むなら止めはしませんが……","ENG":"If that is your wish, I will not stop you...","TWN":"如果你堅持，我也不會阻攔…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"당신의 도움이 없으면 저 아이는 살아남지 못할 텐데요?","JPN":"あなたが助けてあげないと、あの子は死んでしまいますよ？","ENG":"But then, that child will not be able to survive without your help.","TWN":"但沒有你的幫助，那個孩子恐怕就要活不下去了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"え……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"아가씨! 정신을 잃으면 안 됩니다!","JPN":"お嬢様！　気を失ってはいけません！","ENG":"Miss Morgana! Please, stay with me!","TWN":"小姐！保持清醒！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L22_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_NULL","text":{"KOREA":"모르가나 아가씨가 위독합니다! 상처가 지혈이 안돼요!","JPN":"モルガナお嬢様が危険です！　止血できません！","ENG":"Miss Morgana is severely injured! Her wound keeps bleeding!","TWN":"莫甘娜小姐情況危急！傷口止不住血！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"전 선발대일 뿐입니다. 곧 마왕의 본대가 이 세계를 끝내기 위해 직접 움직일 테니까요.","JPN":"私はただの先発隊です。すぐ魔王の分隊がこの世界を終わらせるためにやってくるでしょう。","ENG":"I am just the spearhead. The Demon Lord's main forces will soon mobilize to bring doom upon the world herself.","TWN":"我只是打頭陣。很快魔王的主力部隊就會親自行動，終結這個世界。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너… 목적이 뭐지?","JPN":"アナタ……目的は何？","ENG":"What... is your objective in all of this?","TWN":"你…目的是什麼？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"마왕이 인류를 멸망시키면, 그 영혼에 기생하는 너도 무사하지 못할 텐데?","JPN":"魔王が人類を滅亡させれば、その魂に寄生しているアナタも無事では済まない。","ENG":"If the Demon Lord annihilates all of humanity, you will not be safe either as you need souls to leech from.","TWN":"如果魔王滅絕人類，寄生在人類靈魂上的你也不會倖免吧？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"마왕의 존재는 종말 그 자체이자, 멈출 수 없는 흐름입니다.","JPN":"魔王の存在は終末そのまのであり、止められない流れです。","ENG":"The existence of the Demon Lord is the end itself. There is no stopping it.","TWN":"魔王的存在本身就是終結，是無法停止的洪流。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"저항하다 부서지기보다, 그 흐름에 몸을 맡기는 쪽을 택했을 뿐이죠.","JPN":"私は流れに逆らい壊されるより、身を任せる方を選んだまでですよ。","ENG":"So instead of resisting, I have chosen to surrender to the flow.","TWN":"我只是選擇了順應這股洪流，而不是在抵抗中破碎。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"그리고 전…","JPN":"それに、私は……","ENG":"Also...","TWN":"以及…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"당신이 거둔 그 아이가 어떤 최후를 맞게 될지. 감상하고 싶거든요.","JPN":"あなたが引き取ったあの子がどんな最期を迎えるか、鑑賞したいので。","ENG":"I am curious to witness the outcome that awaits the child you have taken in.","TWN":"我想看看你收養的那個孩子，會有怎樣的結局。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WOMAN_ROOT_NPC_NULL","text":{"KOREA":"호박 악마가…","JPN":"カボチャ悪魔が……","ENG":"The pumpkin head disappeared...","TWN":"南瓜魔鬼…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"사라졌어?","JPN":"消えた？","ENG":"Where did he go?","TWN":"消失了？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WOMAN_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOUTH_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나!","JPN":"モルガナ！","ENG":"Morgana!","TWN":"莫甘娜！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"멀린 씨! 어쩌면 좋죠? 모르가나가 상처를 전혀 회복하지 못하고 있어요!","JPN":"マーリンさん！　どうしましょう？　モルガナの傷が回復しません！","ENG":"Merlin! I don't know what I should do! Morgana isn't recovering from her wound at all!","TWN":"梅林祭司長！怎麼辦才好？莫甘娜的傷口完全沒有恢復！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이미 성흔이 검게 물들고 있어.","JPN":"すでに聖痕が黒く染まっているわ。","ENG":"Her Stigmata has already started to turn black.","TWN":"聖痕已經變黑了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"남은 유일한 방법은…","JPN":"残っている唯一の方法は……","ENG":"The only thing I can do is...","TWN":"唯一剩下的辦法是…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"곧 돌아올 테니… 기다려.","JPN":"すぐ戻ってくるから……待ちなさい。","ENG":"Wait here. I will be back shortly.","TWN":"我馬上就回來…等我。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"멀린 씨…?","JPN":"マーリンさん……？","ENG":"Merlin...?","TWN":"梅林…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"대체 상황이 어떻게 돌아가고 있는 거지?","JPN":"いったいどうなってるんだ？","ENG":"What the heck's going on right now?","TWN":"到底是怎麼回事？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOUTH_ROOT_NPC_NULL","text":{"KOREA":"다들 봤어요? 제사장님이 악마와 맞설 때 쓰던 힘 말이예요.","JPN":"みんな、見ましたか？　祭祀長が悪魔と立ち向かう時に使っていた力です。","ENG":"Did you all see? The power the High Priest used while fighting the devil.","TWN":"大家看到了嗎？祭司長對抗魔鬼時使用的力量。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"저도 느꼈습니다.","JPN":"私も感じました。","ENG":"I felt it too.","TWN":"我也感覺到了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BLIND_ROOT_NPC_NULL","text":{"KOREA":"그 불길한 기운은… 틀림없는 악마의 힘이었죠.","JPN":"あの不吉な気配……確かに悪魔の力でしたよ。","ENG":"That ominous energy... It was definitely the power of the devil.","TWN":"那股不祥的氣息…無疑也是魔鬼的力量。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"악마라고…? 그럼 제사장님은 애초에 아발론 왕의 환생이 아니었다는 건가?","JPN":"悪魔だと……？　では、祭祀長はそもそもアバロン王の生まれ変わりじゃなかったのか？","ENG":"A devil...? Then the High Priest isn't the reincarnation of the old king of Avalon?","TWN":"魔鬼…？那祭司長一開始就不是阿瓦隆王的轉世嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WOMAN_ROOT_NPC_NULL","text":{"KOREA":"도대체… 우린 어디서부터 속고 있었던 거죠?","JPN":"いったい……私たちはいつから騙されていたのでしょうか？","ENG":"Since when... were we being fooled?","TWN":"到底…我們從哪裡開始被騙的？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"지금 그런 걸 따질 때가 아닐세!","JPN":"今はそれどころではない！","ENG":"Now is not the time to think about that!","TWN":"現在不是計較這些的時候！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"어서 위급한 환자부터 옮기자고!","JPN":"緊急の怪我人から急いで運ぼう！","ENG":"We must move the critical patient first!","TWN":"快把重症病人送去治療！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀… 린…","JPN":"マー……リン……","ENG":"Mer... lin...","TWN":"梅…林…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…추워…","JPN":"寒い……","ENG":"... I'm so cold...","TWN":"…好冷…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나는 제가 데려갈게요!","JPN":"モルガナは私が連れて行きます！","ENG":"I'll carry Morgana!","TWN":"我送莫甘娜過去！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"다들 길을 여세요! 환자를 보내야 합니다!","JPN":"みなさん、道を開けてください！　患者を運びます！","ENG":"Everyone, make way for the patient!","TWN":"大家讓開！要送病人過去！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GUIDE_ROOT_NPC_RESEARCH","text":{"KOREA":"저희가 수술을 준비해두겠습니다!","JPN":"私たちは手術の用意をしておきます！","ENG":"We'll make preparations for the surgery!","TWN":"我們會準備好手術的！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};